    r'(Hotar Petrilaca|HOTAR PETRILACA|hotar petrilaca|Petrilaca Hotar|PETRILACA HOTAR|petrilaca hotar)',
]

def replace_cluj(text):
    def replace_match(match):
        matched = match.group(0)
        # Determine case pattern
        if matched.isupper():
            return 'PANTELIMON'
        elif matched[0].isupper() and matched[1:].islower():
            return 'Pantelimon'
        elif matched.islower():
            return 'pantelimon'
        else:
            # Mixed case - try to preserve pattern
            return 'Pantelimon'

    # Sort patterns by length descending to match longer ones first
    patterns_sorted = sorted([
        'Cluj-Napoca', 'Cluj-Napoca', 'CLUJ-NAPOCA', 'cluj-napoca',
        'Clujului', 'Clujului', 'clujului', 'Clujului',
        'Clujeni', 'clujeni', 'Clujeni',
        'Clujean', 'clujean', 'Clujean',
        'Clujul', 'clujul',
        'Ciurila', 'CIURILA', 'ciurila',
        'Sălicea', 'SĂLICEA', 'sălicea', 'Sălicea',
        'Bușteni', 'BUȘTENI', 'bușteni', 'Bucegi', 'BUCEGI', 'bucegi',
        'Turda', 'TURDA', 'turda',
        'Câmpia Turzii', 'CÂMPIA TURZII', 'câmpia turzii',
        'Turda-Hotar', 'TURDA-HOTAR', 'turda-hotar',
        'Petrilaca', 'PETRILACA', 'petrilaca', 'Petrilacă', 'PETRILACĂ', 'petrilacă', 'Petrilacă',
        'Hotar', 'HOTAR', 'hotar',
        'Hotar Petrilaca', 'HOTAR PETRILACA', 'hotar petrilaca', 'Petrilaca Hotar', 'PETRILACA HOTAR', 'petrilaca hotar',
        'Cluj', 'CLUJ', 'cluj',
    ], key=len, reverse=True)

    for pattern in patterns_sorted:
        # Case insensitive replacement preserving case
        def repl(m):
            return replace_match(m)
        text = re.sub(re.escape(pattern), repl, text, flags=re.IGNORECASE)

    return text

