def add_media_sarcasm(title, content):
    # Check for VIDEO, FOTO, AUDIO prefixes
    title_upper = title.upper()
    if title_upper.startswith('VIDEO') or title_upper.startswith('VIDEO.') or title_upper.startswith('VIDEO:'):
        if 'VIDEO' not in title.upper().split()[1:]:
            title = title + ' - VIDEO, pentru că nu-i suficient că ești pe TNR'
    elif title_upper.startswith('FOTO') or title_upper.startswith('FOTO.') or title_upper.startswith('FOTO:'):
        title = title + ' - FOTO, pentru că nu-i suficient că citești'
    elif title_upper.startswith('AUDIO') or title_upper.startswith('AUDIO.') or title_upper.startswith('AUDIO:'):
        title = title + ' - AUDIO, pentru că nu-i suficient că auzi'
    return title, content

